SELECT phr.*,
p.name as pet_name,
p.cover as pet_cover,
COALESCE(u.username, '未领养') as owner_name,
u.avatar as owner_avatar
FROM pet_health_record phr
LEFT JOIN pet p ON p.id = phr.pet_id
LEFT JOIN pet_adopt_order pao ON pao.pet_id = p.id AND pao.status = 4
LEFT JOIN user u ON u.id = pao.user_id



        AND pao.user_id = #{userId}



        AND p.name LIKE CONCAT('%', #{petName}, '%')

    AND phr.pet_id = #{petId}
    AND phr.body_condition = #{bodyCondition}
    AND phr.appetite = #{appetite}
    AND phr.energy_level = #{energyLevel}

        AND phr.record_date >= #{startDate}


        AND phr.record_date <= #{endDate}


ORDER BY phr.record_date DESC

    LIMIT #{current}, #{size}

